import{_ as s,o as e,c as i,aA as t}from"./chunks/framework.CAIZw9CR.js";const k=JSON.parse('{"title":"Hello KRK","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/first_steps/01_hello_krk.md","filePath":"tutorials/first_steps/01_hello_krk.md","lastUpdated":null}'),n={name:"tutorials/first_steps/01_hello_krk.md"};function l(p,a,o,h,r,d){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="Hello-KRK" tabindex="-1">Hello KRK <a class="header-anchor" href="#Hello-KRK" aria-label="Permalink to &quot;Hello KRK {#Hello-KRK}&quot;">​</a></h1><p>Your first Kraken simulation, running in under two minutes. No Julia script, no <code>run_*_2d(...)</code> call — just a plain text <code>.krk</code> file and a shell command.</p><h2 id="What-is-a-.krk-file?" tabindex="-1">What is a <code>.krk</code> file? <a class="header-anchor" href="#What-is-a-.krk-file?" aria-label="Permalink to &quot;What is a \`.krk\` file? {#What-is-a-.krk-file?}&quot;">​</a></h2><p>A Kraken config file (<code>.krk</code>) is a declarative description of a simulation — domain, physics, boundary conditions, run length, outputs. It looks like this:</p><div class="language-krk vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">krk</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Simulation cavity D2Q9</span></span>
<span class="line"><span>Domain  L = 1.0 x 1.0  N = 128 x 128</span></span>
<span class="line"><span>Physics nu = 0.128</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Boundary north velocity(ux = 0.1, uy = 0)</span></span>
<span class="line"><span>Boundary south wall</span></span>
<span class="line"><span>Boundary east  wall</span></span>
<span class="line"><span>Boundary west  wall</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Run 60000 steps</span></span>
<span class="line"><span>Output vtk every 10000 [rho, ux, uy]</span></span></code></pre></div><p>That&#39;s the lid-driven cavity at Re = 100. Every <code>.krk</code> file has the same shape: one <code>Simulation</code>, one <code>Domain</code>, one <code>Physics</code>, a handful of <code>Boundary</code> lines, a <code>Run</code> duration, and one or more <code>Output</code> lines.</p><h2 id="Run-it" tabindex="-1">Run it <a class="header-anchor" href="#Run-it" aria-label="Permalink to &quot;Run it {#Run-it}&quot;">​</a></h2><p>The repository ships a CLI wrapper at <code>bin/kraken</code>. Symlink it once:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pwd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)/bin/kraken&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.local/bin/kraken</span></span></code></pre></div><p>Then from anywhere in the project:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kraken</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/cavity.krk</span></span></code></pre></div><p>That&#39;s it. The solver picks up the file, runs on GPU if available (CUDA auto-detected, Metal/ROCm selectable), and writes VTK snapshots to <code>output/cavity_*.vtr</code> every 10 000 steps.</p><p>Open the result in ParaView:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">paraview</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output/cavity.pvd</span></span></code></pre></div><h2 id="Inspect-without-running" tabindex="-1">Inspect without running <a class="header-anchor" href="#Inspect-without-running" aria-label="Permalink to &quot;Inspect without running {#Inspect-without-running}&quot;">​</a></h2><p>Use <code>kraken info</code> to parse the file and see how Kraken understands it, including the sanity check on <code>τ</code> and Mach number:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kraken</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> info</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/cavity.krk</span></span></code></pre></div><p>This prints the resolved parameters and flags any instability risk (<code>τ &lt; 0.55</code> or <code>Ma &gt; 0.1</code>) without launching the simulation.</p><h2 id="Override-parameters-from-the-CLI" tabindex="-1">Override parameters from the CLI <a class="header-anchor" href="#Override-parameters-from-the-CLI" aria-label="Permalink to &quot;Override parameters from the CLI {#Override-parameters-from-the-CLI}&quot;">​</a></h2><p>Any scalar in <code>Physics</code> can be overridden at launch time. Want Re = 1000 instead of Re = 100? Lower the viscosity without editing the file:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kraken</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/cavity.krk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --nu=0.0128</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --max_steps=200000</span></span></code></pre></div><p>The override syntax is <code>--key=value</code>, matching the keyword arguments accepted by the underlying Julia driver.</p><h2 id="Pick-a-backend" tabindex="-1">Pick a backend <a class="header-anchor" href="#Pick-a-backend" aria-label="Permalink to &quot;Pick a backend {#Pick-a-backend}&quot;">​</a></h2><p>By default the CLI tries CUDA and falls back to CPU. Force one explicitly:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kraken</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/cavity.krk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --backend=cpu</span></span></code></pre></div><p>For Metal (Apple Silicon) and ROCm (AMD GPU) backends, see the <a href="./../../installation">Installation guide</a>.</p><h2 id="What-did-we-just-do?" tabindex="-1">What did we just do? <a class="header-anchor" href="#What-did-we-just-do?" aria-label="Permalink to &quot;What did we just do? {#What-did-we-just-do?}&quot;">​</a></h2><p>The <code>kraken run</code> command is equivalent to:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Kraken, CUDA</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">result </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> run_simulation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;examples/cavity.krk&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; backend </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> CUDABackend</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">())</span></span></code></pre></div><p>…but without needing a Julia REPL, a project activation, or a wrapper script. The <code>.krk</code> file is the <strong>single source of truth</strong> for the simulation setup.</p><h2 id="Where-next?" tabindex="-1">Where next? <a class="header-anchor" href="#Where-next?" aria-label="Permalink to &quot;Where next? {#Where-next?}&quot;">​</a></h2><ul><li><p><strong><a href="./02_build_a_krk">Build a KRK</a></strong> — construct a <code>.krk</code> from scratch, block by block, with an explanation of every directive.</p></li><li><p><strong><a href="./03_cookbook">Cookbook</a></strong> — recipes for obstacles, STL bodies, spatial boundary profiles, thermal coupling, grid refinement, and more.</p></li><li><p><strong><a href="./../../krk/overview">.krk DSL reference</a></strong> — full directive reference when you need the exhaustive syntax.</p></li></ul>`,32)])])}const u=s(n,[["render",l]]);export{k as __pageData,u as default};
